def normalize_resume(candidate):
    email = candidate.get('email', '').strip()
    if '@' not in email:
        raise RuntimeError('candidate profile missing normalized_email')
    return {'normalized_email': email.lower()}

def run(candidate):
    normalized = normalize_resume(candidate)
    return {'normalized': normalized, 'warnings': []}

def test_warns_on_bad_email():
    candidate = {'email': 'invalid.example.com'}
    result = run(candidate)
    assert result['warnings'] == ['invalid email']
